#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long val, ans;
        scanf("%lld", &ans);
        for (int i = 1; i < N; ++i) {
            scanf("%lld", &val);
            ans = gcd_ll(ans, val);
        }
        printf("%lld\n", ans);
    }
    return 0;
}

